-- Session 3.1 — RLS helpers and policies for the template tables.
--
-- Two security-definer helpers consolidate the per-template authorization
-- logic so child-table policies can short-circuit through them without
-- recursively triggering RLS on `estimate_templates`:
--
--   can_read_template  : system always readable; org needs is_org_member;
--                        profile needs auth.uid match.
--   can_manage_template: system is read-only (writes only via CI migrations);
--                        org needs can_manage_org; profile needs auth.uid match.
--
-- Child tables (template_stages → template_works → template_resource_lines)
-- inherit access by joining up to the owning estimate_template and calling
-- the helper. Mirrors the Session 2 org_documents → org_document_versions
-- chain pattern.

create or replace function public.can_read_template(p_owner_kind text, p_owner_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select case
    when p_owner_kind = 'system' then true
    when p_owner_kind = 'org' and p_owner_id is not null then public.is_org_member(p_owner_id)
    when p_owner_kind = 'profile' and p_owner_id is not null then p_owner_id = auth.uid()
    else false
  end;
$$;

create or replace function public.can_manage_template(p_owner_kind text, p_owner_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select case
    when p_owner_kind = 'system' then false
    when p_owner_kind = 'org' and p_owner_id is not null then public.can_manage_org(p_owner_id)
    when p_owner_kind = 'profile' and p_owner_id is not null then p_owner_id = auth.uid()
    else false
  end;
$$;

revoke all on function public.can_read_template(text, uuid) from public;
revoke all on function public.can_manage_template(text, uuid) from public;
grant execute on function public.can_read_template(text, uuid) to authenticated;
grant execute on function public.can_manage_template(text, uuid) to authenticated;

grant select, insert, update, delete on table
  public.estimate_templates,
  public.template_stages,
  public.template_works,
  public.template_resource_lines
to authenticated;

alter table public.estimate_templates enable row level security;
alter table public.template_stages enable row level security;
alter table public.template_works enable row level security;
alter table public.template_resource_lines enable row level security;

-- estimate_templates: direct authorization on (owner_kind, owner_id).

create policy estimate_templates_select on public.estimate_templates
  for select
  to authenticated
